@page "/"
@using SkiaSharp
@using SkiaSharp.Views.Blazor

<button @onclick="ToggleCanvases">Toggle All</button>
<button @onclick="SwapCanvases">Swap Canvases</button>
<button @onclick="RapidSwap">Rapid Swap (20x, no delay)</button>

@if (showCanvases)
{
    @foreach (var id in canvasIds)
    {
        <div @key="id">
            <CanvasWrapper Id="id" />
        </div>
    }
}

@code {
    bool showCanvases = true;
    List<int> canvasIds = new() { 1, 2, 3, 4, 5 };
    int nextId = 6;

    void ToggleCanvases() => showCanvases = !showCanvases;
    void SwapCanvases() {
        canvasIds = Enumerable.Range(nextId, 5).ToList();
        nextId += 5;
    }
    async Task RapidSwap() {
        for (int i = 0; i < 20; i++) {
            if (i % 3 == 0) showCanvases = !showCanvases;
            else SwapCanvases();
            StateHasChanged();
            await Task.Yield();
        }
    }
}

@using SkiaSharp
@using SkiaSharp.Views.Blazor
@implements IDisposable

<SKCanvasView OnPaintSurface="OnPaintSurface" style="width:150px;height:150px;" />

@code {
    [Parameter] public int Id { get; set; }
    void OnPaintSurface(SKPaintSurfaceEventArgs e) {
        e.Surface.Canvas.Clear(SKColors.CornflowerBlue);
    }
    public void Dispose() => Console.WriteLine($"CanvasWrapper #{Id} disposing");
}
